}

// ─── Config ──────────────────────────────────────────────────────────────────

export interface LspExtensionConfig {
	enabled: boolean;
	autoStart: boolean;
	idleTimeoutMs: number;
	syncContent: boolean;
	autoDiagnostics: boolean;
	servers: Record<string, { enabled?: boolean; command?: string[] }>;
	customServers: LSPServerConfig[];
}

import * as fs from "node:fs";
import * as path from "node:path";
import type { LspExtensionConfig, LSPServerConfig } from "./types.ts";

const DEFAULT_CONFIG: LspExtensionConfig = {
	enabled: true,
	autoStart: true,
	idleTimeoutMs: 300_000,
	syncContent: true,
	autoDiagnostics: true,
	servers: {},
	customServers: [],
};

export function loadConfig(cwd: string): { config: LspExtensionConfig; path: string } {
	const configPath = path.join(cwd, ".pi", "pi-lsp.json");
	if (!fs.existsSync(configPath)) {
		return { config: { ...DEFAULT_CONFIG }, path: configPath };
	}
	try {
		const raw = fs.readFileSync(configPath, "utf-8");
		const parsed = JSON.parse(raw) as Partial<LspExtensionConfig>;
		return {
			config: {
				enabled: parsed.enabled ?? DEFAULT_CONFIG.enabled,
				autoStart: parsed.autoStart ?? DEFAULT_CONFIG.autoStart,
				idleTimeoutMs: parsed.idleTimeoutMs ?? DEFAULT_CONFIG.idleTimeoutMs,
				syncContent: parsed.syncContent ?? DEFAULT_CONFIG.syncContent,
				autoDiagnostics: parsed.autoDiagnostics ?? DEFAULT_CONFIG.autoDiagnostics,
				servers: { ...DEFAULT_CONFIG.servers, ...(parsed.servers ?? {}) },
				customServers: validateCustomServers(parsed.customServers),
			},
			path: configPath,
		};
	} catch {
		return { config: { ...DEFAULT_CONFIG }, path: configPath };
	}
}

function validateCustomServers(servers: unknown): LSPServerConfig[] {
	if (!Array.isArray(servers)) return [];
	const valid: LSPServerConfig[] = [];
	for (const server of servers) {
		if (
			typeof server === "object" && server !== null &&
			typeof (server as Record<string, unknown>).language === "string" &&
			Array.isArray((server as Record<string, unknown>).command) &&
			Array.isArray((server as Record<string, unknown>).extensions)
		) {
			valid.push(server as LSPServerConfig);
		}
	}
	return valid;
}

import { ChildProcess, spawn } from "node:child_process";
import type { JsonRpcRequest, JsonRpcNotification, JsonRpcResponse } from "../types.ts";

export interface ConnectionEvents {
	onResponse: (msg: JsonRpcResponse) => void;
	onNotification: (method: string, params: unknown) => void;
	onError: (error: Error) => void;
	onClose: () => void;
}

export class Connection {
	private proc: ChildProcess | null = null;
	private buffer = "";
	private nextId = 1;
	private pending = new Map<number | string, { resolve: (value: unknown) => void; reject: (error: Error) => void }>();
	private handlers: ConnectionEvents;
	private closed = false;

	constructor(handlers: ConnectionEvents) {
		this.handlers = handlers;
	}

	get isClosed(): boolean {
		return this.closed;
	}

	start(command: string[], cwd: string): void {
		this.proc = spawn(command[0], command.slice(1), {
			cwd,
			stdio: ["pipe", "pipe", "pipe"],
		});

		this.proc.stdout?.on("data", (chunk: Buffer) => {
			this.buffer += chunk.toString("utf-8");
			this.parseMessages();
		});

		this.proc.stderr?.on("data", (chunk: Buffer) => {
			// LSP servers log to stderr; ignore or forward
			void chunk;
		});

		this.proc.on("error", (err) => {
			this.handlers.onError(err);
		});

		this.proc.on("close", () => {
			this.closed = true;
			for (const [id, pending] of this.pending) {
				pending.reject(new Error(`Connection closed (pending request ${id})`));
			}
			this.pending.clear();
			this.handlers.onClose();
		});
	}

	sendRequest(method: string, params?: unknown): Promise<unknown> {
		return new Promise((resolve, reject) => {
			if (this.closed || !this.proc?.stdin?.writable) {
				reject(new Error("Connection is closed"));
				return;
			}
			const id = this.nextId++;
			const msg: JsonRpcRequest = { jsonrpc: "2.0", id, method, params };
			this.pending.set(id, { resolve, reject });
			this.write(msg);
		});
	}

	sendNotification(method: string, params?: unknown): void {
		if (this.closed || !this.proc?.stdin?.writable) return;
		const msg: JsonRpcNotification = { jsonrpc: "2.0", method, params };
		this.write(msg);
	}

	private write(msg: JsonRpcRequest | JsonRpcNotification): void {
		const body = JSON.stringify(msg);
		const header = `Content-Length: ${Buffer.byteLength(body, "utf-8")}\r\n\r\n`;
		this.proc!.stdin!.write(header + body, "utf-8");
	}

	private parseMessages(): void {
		while (this.buffer.length > 0) {
			const headerEnd = this.buffer.indexOf("\r\n\r\n");
			if (headerEnd === -1) break;

			const header = this.buffer.substring(0, headerEnd);
			const match = header.match(/^Content-Length:\s*(\d+)/i);
			if (!match) {
				this.buffer = this.buffer.substring(headerEnd + 4);
				continue;
			}

			const contentLength = Number.parseInt(match[1], 10);
			const bodyStart = headerEnd + 4;
			const bodyEnd = bodyStart + contentLength;

			if (this.buffer.length < bodyEnd) break;

			const body = this.buffer.substring(bodyStart, bodyEnd);
			this.buffer = this.buffer.substring(bodyEnd);

			try {
				const msg = JSON.parse(body) as JsonRpcResponse;
				if ("id" in msg && ("result" in msg || "error" in msg)) {
					const pending = this.pending.get(msg.id);
					if (pending) {
						this.pending.delete(msg.id);
						if (msg.error) {
							pending.reject(new Error(`LSP error ${msg.error.code}: ${msg.error.message}`));
						} else {
							pending.resolve(msg.result);
						}
					}
					this.handlers.onResponse(msg);
				} else if ("method" in msg) {
					this.handlers.onNotification((msg as unknown as { method: string }).method, (msg as unknown as { params?: unknown }).params);
				}
			} catch {
				// Ignore malformed messages
			}
		}
	}

	kill(): void {
		this.closed = true;
		for (const [, pending] of this.pending) {
			pending.reject(new Error("Connection killed"));
		}
		this.pending.clear();
		this.proc?.kill();
		this.proc = null;
	}
}

export interface ClientCapabilities {
	textDocument?: {
		hover?: { dynamicRegistration?: boolean };
		definition?: { dynamicRegistration?: boolean; linkSupport?: boolean };
		typeDefinition?: { dynamicRegistration?: boolean };
		references?: { dynamicRegistration?: boolean };
		rename?: { dynamicRegistration?: boolean; prepareSupport?: boolean };
		documentSymbol?: { dynamicRegistration?: boolean; hierarchicalDocumentSymbolSupport?: boolean };
		publishDiagnostics?: { relatedInformation?: boolean };
		codeAction?: { dynamicRegistration?: boolean };
		formatting?: { dynamicRegistration?: boolean };
		rangeFormatting?: { dynamicRegistration?: boolean };
		synchronization?: { dynamicRegistration?: boolean; willSave?: boolean; willSaveWaitUntil?: boolean; didSave?: boolean };
	};
	workspace?: {
		symbol?: { dynamicRegistration?: boolean };
		applyEdit?: boolean;
		workspaceEdit?: { documentChanges?: boolean };
	};
}

export interface ServerCapabilities {
	textDocumentSync?: unknown;
	hoverProvider?: boolean;
	definitionProvider?: boolean;
	typeDefinitionProvider?: boolean | { workDoneProgress?: boolean };
	referencesProvider?: boolean;
	renameProvider?: boolean | { prepareProvider?: boolean };
	documentSymbolProvider?: boolean;
	workspaceSymbolProvider?: boolean;
	codeActionProvider?: boolean;
	documentFormattingProvider?: boolean;
	documentRangeFormattingProvider?: boolean;
	executeCommandProvider?: { commands: string[] };
}

export function buildClientCapabilities(): ClientCapabilities {
	return {
		textDocument: {
			hover: { dynamicRegistration: false },
			definition: { dynamicRegistration: false, linkSupport: true },
			typeDefinition: { dynamicRegistration: false },
			references: { dynamicRegistration: false },
			rename: { dynamicRegistration: false, prepareSupport: true },
			documentSymbol: { dynamicRegistration: false, hierarchicalDocumentSymbolSupport: true },
			publishDiagnostics: { relatedInformation: true },
			codeAction: { dynamicRegistration: false },
			formatting: { dynamicRegistration: false },
			rangeFormatting: { dynamicRegistration: false },
			synchronization: { dynamicRegistration: false, willSave: false, willSaveWaitUntil: false, didSave: true },
		},
		workspace: {
			symbol: { dynamicRegistration: false },
			applyEdit: true,
			workspaceEdit: { documentChanges: true },
		},
	};
}

export function buildInitializeParams(rootUri: string, capabilities: ClientCapabilities): Record<string, unknown> {
	return {
		processId: process.pid,
		rootUri,
		capabilities,
		trace: "off",
		workspaceFolders: [{ uri: rootUri, name: "root" }],
	};
}

export function parseServerCapabilities(result: unknown): ServerCapabilities {
	if (typeof result !== "object" || result === null) return {};
	return result as ServerCapabilities;
}

import { Connection } from "./connection.ts";
import { buildClientCapabilities, buildInitializeParams, parseServerCapabilities, type ServerCapabilities } from "./capabilities.ts";
import { LSPClientState } from "../types.ts";

const INIT_TIMEOUT_MS = 30_000;
const SHUTDOWN_TIMEOUT_MS = 5_000;

export class Lifecycle {
	private conn: Connection;
	private _capabilities: ServerCapabilities = {};
	private _state: LSPClientState = LSPClientState.Stopped;
	private rootUri: string;

	constructor(conn: Connection, rootUri: string) {
		this.conn = conn;
		this.rootUri = rootUri;
	}

	get capabilities(): ServerCapabilities {
		return this._capabilities;
	}

	get state(): LSPClientState {
		return this._state;
	}

	async initialize(): Promise<ServerCapabilities> {
		this._state = LSPClientState.Initializing;
		const caps = buildClientCapabilities();
		const params = buildInitializeParams(this.rootUri, caps);

		const result = await Promise.race([
			this.conn.sendRequest("initialize", params),
			timeout(INIT_TIMEOUT_MS, "initialize"),
		]);

		this._capabilities = parseServerCapabilities(result);
		this.conn.sendNotification("initialized", {});
		this._state = LSPClientState.Ready;
		return this._capabilities;
	}

	async shutdown(): Promise<void> {
		if (this._state !== LSPClientState.Ready) return;
		this._state = LSPClientState.ShuttingDown;
		try {
			await Promise.race([
				this.conn.sendRequest("shutdown"),
				timeout(SHUTDOWN_TIMEOUT_MS, "shutdown"),
			]);
		} catch {
			// Best-effort shutdown
		}
		this.conn.sendNotification("exit");
		this._state = LSPClientState.Stopped;
	}
}

function timeout(ms: number, op: string): Promise<never> {
	return new Promise((_, reject) => {
		setTimeout(() => reject(new Error(`LSP ${op} timed out after ${ms}ms`)), ms);
	});
}

import { Connection, type ConnectionEvents } from "./connection.ts";
import { Lifecycle } from "./lifecycle.ts";
import { LSPClientState, type Diagnostic } from "../types.ts";

export class LSPClient {
	private conn: Connection;
	private lifecycle: Lifecycle;
	private diagnosticsMap = new Map<string, Diagnostic[]>();
	private state: LSPClientState = LSPClientState.Stopped;
	private lastActivityAt = Date.now();

	constructor(
		private language: string,
		private cwd: string,
	) {
		const events: ConnectionEvents = {
			onResponse: () => {},
			onNotification: (method, params) => this.handleNotification(method, params),
			onError: () => {},
			onClose: () => {
				this.state = LSPClientState.Stopped;
			},
		};
		this.conn = new Connection(events);
		const rootUri = pathToUri(cwd);
		this.lifecycle = new Lifecycle(this.conn, rootUri);
	}

	get clientState(): LSPClientState {
		return this.state;
	}

	get lastActivity(): number {
		return this.lastActivityAt;
	}

	getDiagnostics(fileUri: string): Diagnostic[] {
		return this.diagnosticsMap.get(fileUri) ?? [];
	}

	getAllDiagnostics(): Map<string, Diagnostic[]> {
		return new Map(this.diagnosticsMap);
	}

	async start(command: string[]): Promise<void> {
		if (this.state !== LSPClientState.Stopped) return;
		this.conn.start(command, this.cwd);
		await this.lifecycle.initialize();
		this.state = LSPClientState.Ready;
		this.lastActivityAt = Date.now();
	}

	async shutdown(): Promise<void> {
		if (this.state !== LSPClientState.Ready) {
			this.conn.kill();
			return;
		}
		await this.lifecycle.shutdown();
		this.conn.kill();
		this.state = LSPClientState.Stopped;
	}

	async sendRequest(method: string, params?: unknown): Promise<unknown> {
		if (this.state !== LSPClientState.Ready) {
			throw new Error(`Client not ready (state=${this.state})`);
		}
		this.lastActivityAt = Date.now();
		return this.conn.sendRequest(method, params);
	}

	sendNotification(method: string, params?: unknown): void {
		if (this.state !== LSPClientState.Ready) return;
		this.lastActivityAt = Date.now();
		this.conn.sendNotification(method, params);
	}

	private handleNotification(method: string, params: unknown): void {
		if (method === "textDocument/publishDiagnostics") {
			const p = params as { uri?: string; diagnostics?: Diagnostic[] };
			if (typeof p.uri === "string") {
				this.diagnosticsMap.set(p.uri, p.diagnostics ?? []);
			}
		}
	}
}

export function pathToUri(filePath: string): string {
	const absolute = filePath.startsWith("/") ? filePath : filePath;
	return `file://${absolute}`;
}

export function uriToPath(uri: string): string {
	return uri.replace(/^file:\/\//, "");
}

import * as fs from "node:fs";
import * as path from "node:path";
import type { LSPServerConfig } from "../types.ts";

export const DEFAULT_SERVERS: LSPServerConfig[] = [
	{
		language: "typescript",
		command: ["npx", "typescript-language-server", "--stdio"],
		extensions: [".ts", ".tsx", ".js", ".jsx"],
		detectionFiles: ["tsconfig.json", "package.json"],
		installHint: "npm install -g typescript-language-server typescript",
	},
	{
		language: "python",
		command: ["pylsp", "--stdio"],
		extensions: [".py"],
		detectionFiles: ["requirements.txt", "pyproject.toml", "setup.py"],
		installHint: "pip install python-lsp-server",
	},
	{
		language: "rust",
		command: ["rust-analyzer"],
		extensions: [".rs"],
		detectionFiles: ["Cargo.toml"],
		installHint: "rustup component add rust-analyzer",
	},
	{
		language: "go",
		command: ["gopls", "serve"],
		extensions: [".go"],
		detectionFiles: ["go.mod"],
		installHint: "go install golang.org/x/tools/gopls@latest",
	},
];

export function detectLanguages(cwd: string): string[] {
	const languages: string[] = [];
	for (const server of DEFAULT_SERVERS) {
		for (const detectionFile of server.detectionFiles) {
			if (fs.existsSync(path.join(cwd, detectionFile))) {
				if (!languages.includes(server.language)) {
					languages.push(server.language);
				}
				break;
			}
		}
	}
	return languages;
}

export function getServerForLanguage(language: string): LSPServerConfig | undefined {
	return DEFAULT_SERVERS.find((s) => s.language === language);
}

export function getLanguageForFile(filePath: string, customServers: LSPServerConfig[] = []): string | undefined {
	const ext = path.extname(filePath);
	const allServers = [...DEFAULT_SERVERS, ...customServers];
	for (const server of allServers) {
		if (server.extensions.includes(ext)) {
			return server.language;
		}
	}
	return undefined;
}

export function getServerForFile(filePath: string, customServers: LSPServerConfig[] = []): LSPServerConfig | undefined {
	const language = getLanguageForFile(filePath, customServers);
	if (!language) return undefined;
	return getServerForLanguage(language) ?? customServers.find((s) => s.language === language);
}

import type { LSPServerConfig, LspExtensionConfig } from "../types.ts";

export function resolveServerConfigs(config: LspExtensionConfig): LSPServerConfig[] {
	// Import default servers and filter by config
	const { DEFAULT_SERVERS } = require("./registry.ts") as { DEFAULT_SERVERS: LSPServerConfig[] };
	const servers: LSPServerConfig[] = [];

	for (const server of DEFAULT_SERVERS) {
		const override = config.servers[server.language];
		if (override?.enabled === false) continue;
		servers.push({
			...server,
			command: override?.command ?? server.command,
			enabled: override?.enabled ?? server.enabled,
		});
	}

	for (const custom of config.customServers) {
		servers.push({ ...custom });
	}

	return servers;
}

export function validateCustomServer(server: unknown): { valid: true; config: LSPServerConfig } | { valid: false; error: string } {
	if (typeof server !== "object" || server === null) {
		return { valid: false, error: "Server must be an object" };
	}
	const s = server as Record<string, unknown>;
	if (typeof s.language !== "string" || !s.language) {
		return { valid: false, error: "language is required and must be a non-empty string" };
	}
	if (!Array.isArray(s.command) || s.command.length === 0 || typeof s.command[0] !== "string") {
		return { valid: false, error: "command must be a non-empty array of strings" };
	}
	if (!Array.isArray(s.extensions) || s.extensions.length === 0) {
		return { valid: false, error: "extensions must be a non-empty array" };
	}
	return {
		valid: true,
		config: {
			language: s.language,
			command: s.command as string[],
			extensions: s.extensions as string[],
			detectionFiles: Array.isArray(s.detectionFiles) ? (s.detectionFiles as string[]) : [],
			installHint: typeof s.installHint === "string" ? s.installHint : undefined,
		},
	};
}

