import * as assert from "node:assert/strict";
import * as test from "node:test";
import { detectLanguages, getLanguageForFile, getServerForFile, getServerForLanguage, DEFAULT_SERVERS } from "../../src/servers/registry.ts";
import * as fs from "node:fs";
import * as path from "node:path";
import * as os from "node:os";

test("DEFAULT_SERVERS includes typescript, python, rust, go", () => {
	const languages = DEFAULT_SERVERS.map((s) => s.language);
	assert.ok(languages.includes("typescript"));
	assert.ok(languages.includes("python"));
	assert.ok(languages.includes("rust"));
	assert.ok(languages.includes("go"));
});

test("detectLanguages detects typescript from package.json", () => {
	const dir = fs.mkdtempSync(path.join(os.tmpdir(), "pi-lsp-test-"));
	try {
		fs.writeFileSync(path.join(dir, "package.json"), "{}");
		const langs = detectLanguages(dir);
		assert.ok(langs.includes("typescript"));
	} finally {
		fs.rmSync(dir, { recursive: true });
	}
});

test("detectLanguages detects rust from Cargo.toml", () => {
	const dir = fs.mkdtempSync(path.join(os.tmpdir(), "pi-lsp-test-"));
	try {
		fs.writeFileSync(path.join(dir, "Cargo.toml"), "[package]\nname = \"test\"");
		const langs = detectLanguages(dir);
		assert.ok(langs.includes("rust"));
		assert.ok(!langs.includes("typescript"));
	} finally {
		fs.rmSync(dir, { recursive: true });
	}
});

test("detectLanguages detects multiple languages", () => {
	const dir = fs.mkdtempSync(path.join(os.tmpdir(), "pi-lsp-test-"));
	try {
		fs.writeFileSync(path.join(dir, "package.json"), "{}");
		fs.writeFileSync(path.join(dir, "go.mod"), "module test\n");
		const langs = detectLanguages(dir);
		assert.ok(langs.includes("typescript"));
		assert.ok(langs.includes("go"));
	} finally {
		fs.rmSync(dir, { recursive: true });
	}
});

test("detectLanguages returns empty for unknown directory", () => {
	const dir = fs.mkdtempSync(path.join(os.tmpdir(), "pi-lsp-test-"));
	try {
		const langs = detectLanguages(dir);
		assert.deepStrictEqual(langs, []);
	} finally {
		fs.rmSync(dir, { recursive: true });
	}
});

