	assert.equal(tracker.has("file:///test.ts"), true);
});

test("BufferTracker: delete removes entry", () => {
	const tracker = new BufferTracker();
	tracker.set("file:///test.ts", "content");
	assert.equal(tracker.has("file:///test.ts"), true);
	tracker.delete("file:///test.ts");
	assert.equal(tracker.has("file:///test.ts"), false);
});

test("BufferTracker: clear removes all entries", () => {
	const tracker = new BufferTracker();
	tracker.set("file:///a.ts", "a");
	tracker.set("file:///b.ts", "b");
