import type { LSPClient } from "../client/client.ts";
import type { Diagnostic as LspDiagnostic } from "../types.ts";

export interface DiagnosticsParams {
	file?: string;
}

export interface DiagnosticResult {
	diagnostics: Array<{
		file: string;
		line: number;
		column: number;
		severity: number;
		message: string;
		source?: string;
	}>;
}

export function collectDiagnostics(client: LSPClient, fileUri?: string): DiagnosticResult {
	const allDiags = client.getAllDiagnostics();
	const diagnostics: DiagnosticResult["diagnostics"] = [];

	if (fileUri) {
		const diags = allDiags.get(fileUri) ?? [];
		for (const d of diags) {
			diagnostics.push({
				file: fileUri.replace(/^file:\/\//, ""),
				line: d.range.start.line + 1,
				column: d.range.start.character + 1,
				severity: d.severity ?? 1,
				message: d.message,
				source: d.source,
			});
		}
	} else {
		for (const [uri, diags] of allDiags) {
			for (const d of diags) {
				diagnostics.push({
					file: uri.replace(/^file:\/\//, ""),
					line: d.range.start.line + 1,
					column: d.range.start.character + 1,
					severity: d.severity ?? 1,
					message: d.message,
					source: d.source,
				});
			}
		}
	}

	return { diagnostics };
}

export async function waitForDiagnostics(client: LSPClient, fileUri: string, timeoutMs = 5000): Promise<DiagnosticResult> {
	const startTime = Date.now();
	const existing = client.getDiagnostics(fileUri);
	if (existing.length > 0) {
		return collectDiagnostics(client, fileUri);
	}

	// Poll until diagnostics arrive or timeout
	while (Date.now() - startTime < timeoutMs) {
		await new Promise((resolve) => setTimeout(resolve, 200));
		const current = client.getDiagnostics(fileUri);
		if (current.length > 0) {
			return collectDiagnostics(client, fileUri);
		}
	}

	return collectDiagnostics(client, fileUri);
}

import type { ExtensionAPI, ToolDefinition } from "@mariozechner/pi-coding-agent";
import { Type } from "typebox";
import type { LSPClientPool } from "../client/manager.ts";
import { hover } from "../features/hover.ts";
import { definition } from "../features/definition.ts";
import { references } from "../features/references.ts";
import { rename } from "../features/rename.ts";
import { documentSymbols, workspaceSymbols } from "../features/symbols.ts";
import { collectDiagnostics, waitForDiagnostics } from "../features/diagnostics.ts";
import { codeActions } from "../features/code-actions.ts";
import { formatting } from "../features/formatting.ts";
import { pathToUri } from "../client/client.ts";

interface LspToolDetails {
	tool: string;
	status: "ok" | "error";
}

function lspResult(text: string, isError = false): { content: Array<{ type: "text"; text: string }>; details: LspToolDetails; isError?: boolean } {
	return {
		content: [{ type: "text", text }],
		details: { tool: "lsp", status: isError ? "error" : "ok" },
		...(isError ? { isError: true as const } : {}),
	};
}

export function registerLspTools(pi: ExtensionAPI, pool: LSPClientPool): void {
	// lsp_hover
	pi.registerTool({
		name: "lsp_hover",
		label: "LSP Hover",
		description: "Get type information and documentation for a symbol at a position.",
		parameters: Type.Object({
			file: Type.String({ description: "Absolute file path." }),
			line: Type.Number({ description: "1-based line number." }),
			column: Type.Number({ description: "1-based column number." }),
		}) as never,
		async execute(_id, params, _signal, _onUpdate, _ctx) {
			const p = params as { file: string; line: number; column: number };
			try {
				const client = await pool.getClientForFile(p.file);
				if (!client) return lspResult("No LSP server available for this file type.", true);
				const result = await hover(client, p);
				if (!result) return lspResult("No hover information available.");
				return lspResult(JSON.stringify(result, null, 2));
			} catch (error) {
				return lspResult(error instanceof Error ? error.message : String(error), true);
			}
		},
	} satisfies ToolDefinition);

	// lsp_goto_def
	pi.registerTool({
		name: "lsp_goto_def",
		label: "LSP Go to Definition",
		description: "Find the definition of a symbol at a position.",
		parameters: Type.Object({
			file: Type.String({ description: "Absolute file path." }),
			line: Type.Number({ description: "1-based line number." }),
			column: Type.Number({ description: "1-based column number." }),
		}) as never,
		async execute(_id, params, _signal, _onUpdate, _ctx) {
			const p = params as { file: string; line: number; column: number };
			try {
				const client = await pool.getClientForFile(p.file);
				if (!client) return lspResult("No LSP server available for this file type.", true);
				const result = await definition(client, p);
				return lspResult(JSON.stringify(result.locations, null, 2));
			} catch (error) {
				return lspResult(error instanceof Error ? error.message : String(error), true);
			}
		},
	} satisfies ToolDefinition);

	// lsp_find_refs
	pi.registerTool({
		name: "lsp_find_refs",
		label: "LSP Find References",
		description: "Find all references to a symbol at a position.",
		parameters: Type.Object({
			file: Type.String({ description: "Absolute file path." }),
			line: Type.Number({ description: "1-based line number." }),
			column: Type.Number({ description: "1-based column number." }),
			includeDeclaration: Type.Optional(Type.Boolean({ description: "Include declaration in results. Default: true." })),
		}) as never,
		async execute(_id, params, _signal, _onUpdate, _ctx) {
			const p = params as { file: string; line: number; column: number; includeDeclaration?: boolean };
			try {
				const client = await pool.getClientForFile(p.file);
				if (!client) return lspResult("No LSP server available for this file type.", true);
				const result = await references(client, p);
				return lspResult(JSON.stringify(result.locations, null, 2));
			} catch (error) {
				return lspResult(error instanceof Error ? error.message : String(error), true);
			}
		},
	} satisfies ToolDefinition);

	// lsp_rename
	pi.registerTool({
		name: "lsp_rename",
		label: "LSP Rename",
		description: "Rename a symbol. Returns a preview of changes; requires confirmation.",
		parameters: Type.Object({
			file: Type.String({ description: "Absolute file path." }),
			line: Type.Number({ description: "1-based line number." }),
			column: Type.Number({ description: "1-based column number." }),
			newName: Type.String({ description: "New name for the symbol." }),
		}) as never,
		async execute(_id, params, _signal, _onUpdate, _ctx) {
			const p = params as { file: string; line: number; column: number; newName: string };
			try {
				const client = await pool.getClientForFile(p.file);
				if (!client) return lspResult("No LSP server available for this file type.", true);
				const result = await rename(client, p);
				if (!result) return lspResult("Cannot rename this symbol.");
				return lspResult(JSON.stringify(result.changes, null, 2));
			} catch (error) {
				return lspResult(error instanceof Error ? error.message : String(error), true);
			}
		},
	} satisfies ToolDefinition);

	// lsp_diagnostics
	pi.registerTool({
		name: "lsp_diagnostics",
		label: "LSP Diagnostics",
		description: "Get errors and warnings for a file (or all tracked files if file is omitted).",
		parameters: Type.Object({
			file: Type.Optional(Type.String({ description: "Absolute file path. If omitted, returns diagnostics for all tracked files." })),
		}) as never,
		async execute(_id, params, _signal, _onUpdate, _ctx) {
			const p = params as { file?: string };
			try {
				if (p.file) {
					const client = pool.getClientForFileSync(p.file);
					if (!client) return lspResult("No LSP server available for this file type.", true);
					const fileUri = pathToUri(p.file);
					return lspResult(JSON.stringify(collectDiagnostics(client, fileUri).diagnostics, null, 2));
				}
				return lspResult("No file specified. Provide a file path for diagnostics.");
			} catch (error) {
				return lspResult(error instanceof Error ? error.message : String(error), true);
			}
		},
	} satisfies ToolDefinition);

	// lsp_symbols
	pi.registerTool({
		name: "lsp_symbols",
		label: "LSP Symbols",
		description: "Search workspace symbols or list document symbols for a file.",
		parameters: Type.Object({
			query: Type.Optional(Type.String({ description: "Query string for workspace symbol search." })),
			file: Type.Optional(Type.String({ description: "Absolute file path for document symbols." })),
		}) as never,
		async execute(_id, params, _signal, _onUpdate, _ctx) {
			const p = params as { query?: string; file?: string };
			try {
				if (p.file) {
					const client = await pool.getClientForFile(p.file);
					if (!client) return lspResult("No LSP server available for this file type.", true);
					const result = await documentSymbols(client, p.file);
					return lspResult(JSON.stringify(result.symbols, null, 2));
				}
				if (p.query) {
					const client = await pool.getOrCreate("typescript").catch(() => undefined);
					if (!client) return lspResult("No LSP server available for workspace symbol search.", true);
					const result = await workspaceSymbols(client, p.query);
					return lspResult(JSON.stringify(result.symbols, null, 2));
				}
				return lspResult("Provide either 'query' for workspace search or 'file' for document symbols.", true);
			} catch (error) {
				return lspResult(error instanceof Error ? error.message : String(error), true);
			}
		},
	} satisfies ToolDefinition);

	// lsp_code_actions
	pi.registerTool({
		name: "lsp_code_actions",
		label: "LSP Code Actions",
		description: "Get available quick fixes and refactorings at a position.",
		parameters: Type.Object({
			file: Type.String({ description: "Absolute file path." }),
			line: Type.Number({ description: "1-based line number." }),
			column: Type.Number({ description: "1-based column number." }),
		}) as never,
		async execute(_id, params, _signal, _onUpdate, _ctx) {
			const p = params as { file: string; line: number; column: number };
			try {
				const client = await pool.getClientForFile(p.file);
				if (!client) return lspResult("No LSP server available for this file type.", true);
				const result = await codeActions(client, p);
				return lspResult(JSON.stringify(result.actions, null, 2));
			} catch (error) {
				return lspResult(error instanceof Error ? error.message : String(error), true);
			}
		},
	} satisfies ToolDefinition);

	// lsp_format
	pi.registerTool({
		name: "lsp_format",
		label: "LSP Format",
		description: "Format a file or a range of lines using the language server.",
		parameters: Type.Object({
			file: Type.String({ description: "Absolute file path." }),
			startLine: Type.Optional(Type.Number({ description: "1-based start line for range formatting." })),
			endLine: Type.Optional(Type.Number({ description: "1-based end line for range formatting." })),
		}) as never,
		async execute(_id, params, _signal, _onUpdate, _ctx) {
			const p = params as { file: string; startLine?: number; endLine?: number };
			try {
				const client = await pool.getClientForFile(p.file);
				if (!client) return lspResult("No LSP server available for this file type.", true);
				const result = await formatting(client, p);
				return lspResult(JSON.stringify(result.edits, null, 2));
			} catch (error) {
				return lspResult(error instanceof Error ? error.message : String(error), true);
			}
		},
	} satisfies ToolDefinition);
}

import type { ExtensionAPI, ExtensionContext, ToolResultEvent, ToolResultEventResult } from "@mariozechner/pi-coding-agent";
import { loadConfig } from "../config.ts";
import { detectLanguages } from "../servers/registry.ts";
import { LSPClientPool } from "../client/manager.ts";
import { syncContent, getBufferTracker } from "../sync/content-sync.ts";
import { registerLspTools } from "./tool-registry.ts";
import { pathToUri } from "../client/client.ts";
import { waitForDiagnostics } from "../features/diagnostics.ts";

export function registerPiLsp(pi: ExtensionAPI): void {
	let pool: LSPClientPool | undefined;
	let currentCtx: ExtensionContext | undefined;

	pi.on("session_start", (_event, ctx) => {
		currentCtx = ctx;
		const { config } = loadConfig(ctx.cwd);

		if (!config.enabled) return;

		pool = new LSPClientPool(ctx.cwd, config.idleTimeoutMs, config.customServers);

		// Register tools
		registerLspTools(pi, pool);

		// Auto-start detected language servers
		if (config.autoStart) {
			const languages = detectLanguages(ctx.cwd);
			for (const lang of languages) {
				pool.getOrCreate(lang).catch((error: unknown) => {
					const message = error instanceof Error ? error.message : String(error);
					try {
						ctx.ui.notify(`pi-lsp: failed to start ${lang} server: ${message}`, "warning");
					} catch {
						// UI may not be available
					}
				});
			}
		}
	});

	pi.on("session_shutdown", async () => {
		if (pool) {
			await pool.shutdownAll();
			pool = undefined;
		}
		currentCtx = undefined;
		getBufferTracker().clear();
	});

	// Auto-diagnostics hook: after edit/write tools, sync content and check diagnostics
	pi.on("tool_result", async (event): Promise<ToolResultEventResult | undefined> => {
		if (!pool || !currentCtx) return undefined;
		const { config } = loadConfig(currentCtx.cwd);
		if (!config.autoDiagnostics || !config.syncContent) return undefined;

		const toolResult = event as ToolResultEvent;
		if (toolResult.toolName !== "edit" && toolResult.toolName !== "write") return undefined;

		// Extract file path from the tool result input
		const input = toolResult.input as { file?: string; path?: string } | undefined;
		const filePath = input?.file ?? input?.path;
		if (!filePath) return undefined;

		// Extract text content from result
		const content = toolResult.content;
		if (!Array.isArray(content)) return undefined;

		for (const item of content) {
			if (item.type === "text" && typeof item.text === "string") {
				try {
					await syncContent(pool, filePath, item.text);
					const fileUri = pathToUri(filePath);
					const client = pool.getClientForFileSync(filePath);
					if (client) {
						const diagResult = await waitForDiagnostics(client, fileUri, 3000);
						const errors = diagResult.diagnostics.filter((d) => d.severity <= 2);
						if (errors.length > 0) {
							const diagText = errors
								.map((d) => `  Line ${d.line}: ${d.message}`)
								.join("\n");
							return {
								content: [
									...content,
									{ type: "text" as const, text: `\n⚠️ LSP issues in ${filePath}:\n${diagText}` },
								],
							};
						}
					}
				} catch {
					// Best-effort; don't block on sync failure
				}
			}
		}
		return undefined;
	});
}

