import { Connection, type ConnectionEvents } from "./connection.ts";
import { Lifecycle } from "./lifecycle.ts";
import { LSPClientState, type Diagnostic } from "../types.ts";

export class LSPClient {
	private conn: Connection;
	private lifecycle: Lifecycle;
	private diagnosticsMap = new Map<string, Diagnostic[]>();
	private state: LSPClientState = LSPClientState.Stopped;
	private lastActivityAt = Date.now();
	private language: string;
	private cwd: string;

	constructor(language: string, cwd: string) {
		this.language = language;
		this.cwd = cwd;
		const events: ConnectionEvents = {
			onResponse: () => {},
			onNotification: (method, params) => this.handleNotification(method, params),
			onError: () => {},
			onClose: () => {
				this.state = LSPClientState.Stopped;
			},
		};
		this.conn = new Connection(events);
		const rootUri = pathToUri(cwd);
		this.lifecycle = new Lifecycle(this.conn, rootUri);
	}

	get clientState(): LSPClientState {
		return this.state;
	}

	get lastActivity(): number {
		return this.lastActivityAt;
	}

	getDiagnostics(fileUri: string): Diagnostic[] {
		return this.diagnosticsMap.get(fileUri) ?? [];
	}

	getAllDiagnostics(): Map<string, Diagnostic[]> {
		return new Map(this.diagnosticsMap);
	}

	async start(command: string[]): Promise<void> {
		if (this.state !== LSPClientState.Stopped) return;
		this.conn.start(command, this.cwd);
		await this.lifecycle.initialize();
		this.state = LSPClientState.Ready;
		this.lastActivityAt = Date.now();
	}

	async shutdown(): Promise<void> {
		if (this.state !== LSPClientState.Ready) {
			this.conn.kill();
			return;
		}
		await this.lifecycle.shutdown();
		this.conn.kill();
		this.state = LSPClientState.Stopped;
	}

	async sendRequest(method: string, params?: unknown): Promise<unknown> {
		if (this.state !== LSPClientState.Ready) {
			throw new Error(`Client not ready (state=${this.state})`);
		}
		this.lastActivityAt = Date.now();
		return this.conn.sendRequest(method, params);
	}

	sendNotification(method: string, params?: unknown): void {
		if (this.state !== LSPClientState.Ready) return;
		this.lastActivityAt = Date.now();
		this.conn.sendNotification(method, params);
	}

	private handleNotification(method: string, params: unknown): void {
		if (method === "textDocument/publishDiagnostics") {
			const p = params as { uri?: string; diagnostics?: Diagnostic[] };
			if (typeof p.uri === "string") {
				this.diagnosticsMap.set(p.uri, p.diagnostics ?? []);
			}
		}
	}
}

export function pathToUri(filePath: string): string {
	const absolute = filePath.startsWith("/") ? filePath : filePath;
	return `file://${absolute}`;
}

export function uriToPath(uri: string): string {
	return uri.replace(/^file:\/\//, "");
}

import test from "node:test";
import assert from "node:assert/strict";
import { Connection, type ConnectionEvents } from "../../src/client/connection.ts";

test("Connection: starts not closed", () => {
	const events: ConnectionEvents = {
		onResponse: () => {},
		onNotification: () => {},
		onError: () => {},
		onClose: () => {},
	};
	const conn = new Connection(events);
	// Connection is not closed until killed or the process closes
	assert.equal(conn.isClosed, false);
});

test("Connection: message framing with Content-Length header", () => {
	// Verify the expected message format
	const msg = { jsonrpc: "2.0", id: 1, method: "initialize", params: {} };
	const body = JSON.stringify(msg);
	const header = `Content-Length: ${Buffer.byteLength(body, "utf-8")}\r\n\r\n`;
	const combined = header + body;

	assert.ok(combined.startsWith("Content-Length: "));
	assert.ok(combined.includes("\r\n\r\n"));
	assert.ok(combined.includes('"jsonrpc":"2.0"'));
});

test("Connection: kill sets closed state", () => {
	const events: ConnectionEvents = {
		onResponse: () => {},
		onNotification: () => {},
		onError: () => {},
		onClose: () => {},
	};
	const conn = new Connection(events);
	conn.kill();
	assert.equal(conn.isClosed, true);
});

test("Connection: sendRequest rejects when closed", async () => {
