	};
	const conn = new Connection(events);
	conn.kill();
	await assert.rejects(
		() => conn.sendRequest("initialize"),
		/error/i,
	);
});

test("Connection: sendNotification does not throw when closed", () => {
	const events: ConnectionEvents = {
		onResponse: () => {},
		onNotification: () => {},
		onError: () => {},
		onClose: () => {},
	};
	const conn = new Connection(events);
	conn.kill();
	// Should not throw
	conn.sendNotification("initialized", {});
});

